      assertEquals(Errors.INVALID_MEMBER_EPOCH.code(), response0.errorCode());

      // Verify member state NOT regressed:
      member = group.member(memberId);
      assertEquals(1, member.memberEpoch()); // Still 1, not reset
      assertTrue(member.subscribedTopics().contains("topic-2")); // Still subscribed

      // Verify group didn't regress
      assertEquals(ConsumerGroupState.STABLE, group.state()); // Or expected state
  }
  ```

